        public static string GetBrStockIn(string rmano, string stkoutdocno)
        {
            return $"SELECT pr.iMasterId ItemId,pr.sCode ItemCode,pr.sName ItemName,muts.iMasterId UnitId, rma.sRmaNo RmaNo,muts.sName UnitName,1 Stock,PostedRma =(select  distinct COUNT(hh.iHeaderId) from  tCore_Header_0 hh JOIN tCore_Data_0 dd ON hh.iHeaderId = dd.iHeaderId left join tCore_HeaderData2053_0 hhe on hhe.iHeaderId = hh.iHeaderId left join tCore_Rma_0 rrma on rrma.iBodyId = dd.iBodyId  where  hh.ivouchertype= 2053 and rrma.sRmaNo = '{rmano}' and hhe.StockOutDocNo = '{stkoutdocno}'),Price=(select top 1 iif(fval0=0, fval1, fval0) from mCore_SellingPriceBookDetails where iProductId = pr.iMasterId order by iStartDate desc), d.iTransactionId TxnId, l.iRefId RefId,  l.iLinkId LinkId, l.bBase Base, bClosed Closed,CONCAT(v.sAbbr,':',h.sVoucherNo) LinkVoucherNo,h.iVoucherType LinkVoucherType, h.sVoucherNo DocNo                   FROM tCore_Header_0 h\r\n                    JOIN tCore_Data_0 d ON h.iHeaderId = d.iHeaderId\r\n                    left join tCore_Rma_0 rma on rma.iBodyId = d.iBodyId\r\n                    JOIN tCore_Indta_0 s ON d.iBodyId = s.iBodyId\r\n                    JOIN mCore_Product pr ON pr.iMasterId = s.iProduct\r\n                    join tCore_Links_0 l on l.iTransactionId = d.iTransactionId\r\n                    left join muCore_Product_Units uts on uts.iMasterId = pr.iMasterId left join mCore_Units muts on muts.iMasterId = uts.iDefaultSalesUnit\r\n                    join cCore_Vouchers_0 v on v.iVoucherType = h.iVoucherType WHERE rma.sRmaNo = '{rmano}' and h.iVoucherType = 5380 and bClosed =0";
        }
        public static string GetStockTransferIn(string rmano, string stkoutdocno)
        {
            return $"SELECT pr.iMasterId ItemId,pr.sCode ItemCode,pr.sName ItemName,muts.iMasterId UnitId, rma.sRmaNo RmaNo,muts.sName UnitName,1 Stock,PostedRma =(select  distinct COUNT(hh.iHeaderId) from  tCore_Header_0 hh JOIN tCore_Data_0 dd ON hh.iHeaderId = dd.iHeaderId left join tCore_HeaderData3074_0 hhe on hhe.iHeaderId = hh.iHeaderId left join tCore_Rma_0 rrma on rrma.iBodyId = dd.iBodyId  where  hh.ivouchertype= 3074 and rrma.sRmaNo = '{rmano}' and hhe.StockOutDocNo = '{stkoutdocno}'),Price=(select top 1 iif(fval0=0, fval1, fval0) from mCore_SellingPriceBookDetails where iProductId = pr.iMasterId order by iStartDate desc), d.iTransactionId TxnId, l.iRefId RefId,  l.iLinkId LinkId, l.bBase Base, bClosed Closed,CONCAT(v.sAbbr,':',h.sVoucherNo) LinkVoucherNo,h.iVoucherType LinkVoucherType, h.sVoucherNo DocNo                   FROM tCore_Header_0 h\r\n                    JOIN tCore_Data_0 d ON h.iHeaderId = d.iHeaderId\r\n                    left join tCore_Rma_0 rma on rma.iBodyId = d.iBodyId\r\n                    JOIN tCore_Indta_0 s ON d.iBodyId = s.iBodyId\r\n                    JOIN mCore_Product pr ON pr.iMasterId = s.iProduct\r\n                    join tCore_Links_0 l on l.iTransactionId = d.iTransactionId\r\n                    left join muCore_Product_Units uts on uts.iMasterId = pr.iMasterId left join mCore_Units muts on muts.iMasterId = uts.iDefaultSalesUnit\r\n                    join cCore_Vouchers_0 v on v.iVoucherType = h.iVoucherType WHERE rma.sRmaNo = '{rmano}' and h.iVoucherType = 3073 and bClosed = 0 and not exists (select 1 from tCore_Links_0 lnk join tCore_Data_0 ld on ld.iTransactionId = lnk.iTransactionId join tCore_Rma_0 lrma on lrma.iBodyId = ld.iBodyId where lnk.bBase = 0 and lnk.iRefId = l.iRefId and lrma.sRmaNo = '{rmano}')";
        }
        public static string GetRmaData(string rmano, int outletId)
        {
            return $"select pr.iMasterId ItemId,pr.sCode ItemCode,pr.sName ItemName,muts.iMasterId UnitId, muts.sName UnitName,Price=(select top 1 iif(sld.fval0=0, sld.fval1, fval0) from  mCore_SellingPriceBookHeader sl join mCore_SellingPriceBookDetails sld on sld.iPriceBookId = sl.iPriceBookId where sl.bActive =1 and  sld.bMarkDeleted =  0 and iProductId = pr.iMasterId order by iStartDate desc , iSequenceNumber desc),RmaNo, Qty Stock, pru.VAT , HasScheme = (select count(sh.iHeaderId) Id from tCore_Header_0 sh join tcore_headerdata7938_0 she on she.iHeaderId = sh.iHeaderId  where she.SchemeItem = pr.iMasterId and she.ExpiryDate >= sh.iDate\r\n) from (select iProduct, RmaNo, sum(Qty)  Qty from(SELECT iProduct, rma.sRmaNo RmaNo, 1 Qty FROM tCore_Header_0 JOIN tCore_Data_0 ON tCore_Header_0.iHeaderId = tCore_Data_0.iHeaderId left join tCore_Rma_0 rma on rma.iBodyId = tCore_Data_0.iBodyId JOIN tCore_Indta_0 ON tCore_Data_0.iBodyId = tCore_Indta_0.iBodyId JOIN mCore_Product ON mCore_Product.iMasterId = tCore_Indta_0.iProduct\r\n\r\n    WHERE rma.sRmaNo = '{rmano}' and bUpdateStocks = 1 AND bSuspended = 0 AND bSuspendUpdateStocks = 0 AND tCore_Data_0.iAuthStatus < 2\r\n        AND iProductType<> 1 AND iProductType<> 5\r\n        AND iStatus<> 5 and fQuantityInBase > 0 and tCore_Data_0.iInvTag = {outletId} union all\r\nSELECT iProduct, rma.sRmaNo RmaNo, -1 ReceiptQty\r\n                    FROM tCore_Header_0\r\n                    JOIN tCore_Data_0 ON tCore_Header_0.iHeaderId = tCore_Data_0.iHeaderId\r\n\r\n                    left join tCore_Rma_0 rma on rma.iBodyId = tCore_Data_0.iBodyId\r\n\r\n                    JOIN tCore_Indta_0 ON tCore_Data_0.iBodyId = tCore_Indta_0.iBodyId\r\n                    JOIN mCore_Product ON mCore_Product.iMasterId = tCore_Indta_0.iProduct\r\n\r\n                    WHERE rma.sRmaNo = '{rmano}' and bUpdateStocks = 1 AND bSuspended = 0 AND bSuspendUpdateStocks = 0 AND tCore_Data_0.iAuthStatus < 2\r\n                       AND iProductType<> 1 AND iProductType<> 5\r\n                     AND iStatus<> 5 and fQuantityInBase< 0 and tCore_Data_0.iInvTag = {outletId}) dt group by iProduct, RmaNo\r\n  ) dt join mcore_product pr on pr.imasterid = dt.iProduct join mucore_product pru on pru.imasterid = pr.iMasterId left join muCore_Product_Units uts on uts.iMasterId = pr.iMasterId left join mCore_Units muts on muts.iMasterId = uts.iDefaultSalesUnit   order by iProduct";
        }
        public static string GetSalesReturnCount(string rmano)
        {
            return $"SELECT count(h.iHeaderId) FROM tCore_Header_0 h JOIN tCore_Data_0 d ON h.iHeaderId = d.iHeaderId left join tCore_Rma_0 rma on rma.iBodyId = d.iBodyId JOIN tCore_Indta_0 ind  ON d.iBodyId = ind.iBodyId join mcore_product pr on pr.imasterid = ind.iProduct left join muCore_Product_Units uts on uts.iMasterId = pr.iMasterId left join mCore_Units muts on muts.iMasterId = uts.iDefaultSalesUnit left join tCore_Data_Tags_0 tg on tg.iBodyId = d.iBodyId left join mPos_Member mbr on mbr.iMasterId = tg.iTag1106 WHERE rma.sRmaNo = '{rmano}'    and h.iVoucherType = 1793 ";
        }
        public static string GetSchemeRmaData(int itemid, int outletid, string rmano,  int txndate)
        {
            return $"select dt.RmaNo,dt.Qty TotalQty,pr.iMasterId ItemId, pr.sCode ItemCode,pr.sName ItemName, abs(stk.fQuantity) Qty, abs(stk.mRate) Rate, abs(stk.mGross) Gross, bd.mInput0 Discount, pru.VAT   \r\nfrom (select iProduct, RmaNo, sum(Qty)  Qty from(SELECT iProduct, rma.sRmaNo RmaNo, 1 Qty FROM tCore_Header_0 JOIN tCore_Data_0 ON tCore_Header_0.iHeaderId = tCore_Data_0.iHeaderId left join tCore_Rma_0 rma on rma.iBodyId = tCore_Data_0.iBodyId JOIN tCore_Indta_0 ON tCore_Data_0.iBodyId = tCore_Indta_0.iBodyId JOIN mCore_Product ON mCore_Product.iMasterId = tCore_Indta_0.iProduct\r\n\r\n    WHERE rma.sRmaNo = '{rmano}' and bUpdateStocks = 1 AND bSuspended = 0 AND bSuspendUpdateStocks = 0 AND tCore_Data_0.iAuthStatus < 2\r\n        AND iProductType<> 1 AND iProductType<> 5\r\n        AND iStatus<> 5 and fQuantityInBase > 0 and tCore_Data_0.iInvTag = {outletid} union all\r\nSELECT iProduct, rma.sRmaNo RmaNo, -1 ReceiptQty\r\n                    FROM tCore_Header_0\r\n                    JOIN tCore_Data_0 ON tCore_Header_0.iHeaderId = tCore_Data_0.iHeaderId\r\n\r\n                    left join tCore_Rma_0 rma on rma.iBodyId = tCore_Data_0.iBodyId\r\n\r\n                    JOIN tCore_Indta_0 ON tCore_Data_0.iBodyId = tCore_Indta_0.iBodyId\r\n                    JOIN mCore_Product ON mCore_Product.iMasterId = tCore_Indta_0.iProduct\r\n\r\n                    WHERE rma.sRmaNo = '{rmano}' and bUpdateStocks = 1 AND bSuspended = 0 AND bSuspendUpdateStocks = 0 AND tCore_Data_0.iAuthStatus < 2\r\n                       AND iProductType<> 1 AND iProductType<> 5\r\n                     AND iStatus<> 5 and fQuantityInBase< 0 and tCore_Data_0.iInvTag = {outletid}) dt group by iProduct, RmaNo\r\n  ) dt join mcore_product pr on pr.imasterid = dt.iProduct join mucore_product pru on pru.imasterid = pr.iMasterId left join muCore_Product_Units uts on uts.iMasterId = pr.iMasterId left join mCore_Units muts on muts.iMasterId = uts.iDefaultSalesUnit   \r\n  join tCore_Indta_0 stk on stk.iProduct = pr.iMasterId \r\n  join tCore_Data_0 d on d.iBodyId = stk.iBodyId\r\n  join tcore_headerdata7938_0 she on she.iHeaderId = d.iHeaderId\r\n  join tCore_IndtaBodyScreenData_0 bd on bd.iBodyId = d.iBodyId\r\n  where she.StartDate <= {txndate} and  she.ExpiryDate >= {txndate} and she.Active = 1   and she.SchemeItem = {itemid} order by stk.iProduct";
        }
        public static string GetSalesReturnRmaData(string rmano)
        {
            return $"select * from (SELECT top 1  h.sVoucherNo DocNo,h.idate,mbr.sName MemberName , mbr.iMasterId MemberId, cust.iMasterId CustomerId, cust.sName Customer,outl.iMasterId OutletId, outl.sName OutletName, cost.iMasterId CostCenterId, cost.sName CostCenterName, emp.iMasterId EmployeeId, emp.sName EmployeeName ,pr.iMasterId ItemId,pr.sCode ItemCode,pr.sName ItemName,muts.iMasterId UnitId, muts.sName UnitName,Price=abs(ind.mRate),rma.sRmaNo RmaNo,1  Stock ,1 Qty, pru.VAT , dd.VoucherCode , sd.mVal1 VoucherDiscount, sd.mVal0 Discount  FROM tCore_Header_0 h JOIN tCore_Data_0 d ON h.iHeaderId = d.iHeaderId  left join tCore_Data3334_0 dd on dd.iBodyId = d.iBodyId  left join  tCore_IndtaBodyScreenData_0 sd on sd.iBodyId = d.iBodyId left join tCore_Rma_0 rma on rma.iBodyId = d.iBodyId JOIN tCore_Indta_0 ind  ON d.iBodyId = ind.iBodyId join mcore_product pr on pr.imasterid = ind.iProduct join mucore_product pru on pru.imasterid = pr.iMasterId  left join muCore_Product_Units uts on uts.iMasterId = pr.iMasterId left join mCore_Units muts on muts.iMasterId = uts.iDefaultSalesUnit left join tCore_Data_Tags_0 tg on tg.iBodyId = d.iBodyId left join mPos_Member mbr on mbr.iMasterId = tg.iTag1106 left join mCore_Account cust on cust.iMasterId = d.iBookNo left join mPos_Outlet outl on outl.iMasterId = d.iInvTag left join mCore_CostCenter cost on cost.iMasterId = d.iFaTag left join mPay_Employee emp on emp.iMasterId = tg.iTag800 left join cCore_Vouchers_0 v on v.iVoucherType = h.iVoucherType  WHERE rma.sRmaNo = '{rmano}'  AND bSuspended = 0  AND d.iAuthStatus = 1   and h.iVoucherType = 3334 and not exists(select hh.iHeaderId from  tCore_Header_0 hh JOIN tCore_Data_0 dd ON hh.iHeaderId = dd.iHeaderId left join tCore_HeaderData1793_0 hhe on hhe.iHeaderId = hh.iHeaderId left join tCore_Rma_0 rrma on rrma.iBodyId = dd.iBodyId  where  hh.ivouchertype= 1793 and rrma.sRmaNo = '{rmano}' and hhe.POSDocNo = h.sVoucherNo)  \r\n union  \r\n  SELECT top 1  h.sVoucherNo DocNo,h.idate,mbr.sName MemberName , mbr.iMasterId MemberId, cust.iMasterId CustomerId, cust.sName Customer,outl.iMasterId OutletId, outl.sName OutletName, cost.iMasterId CostCenterId, cost.sName CostCenterName, emp.iMasterId EmployeeId, emp.sName EmployeeName ,pr.iMasterId ItemId,pr.sCode ItemCode,pr.sName ItemName,muts.iMasterId UnitId, muts.sName UnitName,Price=abs(ind.mRate),rma.sRmaNo RmaNo,1  Stock ,1 Qty, pru.VAT ,'' VoucherCode , 0 VoucherDiscount, sd.mVal0 Discount  FROM tCore_Header_0 h JOIN tCore_Data_0 d ON h.iHeaderId = d.iHeaderId  left join tCore_Data3339_0 dd on dd.iBodyId = d.iBodyId  left join  tCore_IndtaBodyScreenData_0 sd on sd.iBodyId = d.iBodyId left join tCore_Rma_0 rma on rma.iBodyId = d.iBodyId JOIN tCore_Indta_0 ind  ON d.iBodyId = ind.iBodyId join mcore_product pr on pr.imasterid = ind.iProduct join mucore_product pru on pru.imasterid = pr.iMasterId  left join muCore_Product_Units uts on uts.iMasterId = pr.iMasterId left join mCore_Units muts on muts.iMasterId = uts.iDefaultSalesUnit left join tCore_Data_Tags_0 tg on tg.iBodyId = d.iBodyId left join mPos_Member mbr on mbr.iMasterId = tg.iTag1106 left join mCore_Account cust on cust.iMasterId = d.iBookNo left join mPos_Outlet outl on outl.iMasterId = d.iInvTag left join mCore_CostCenter cost on cost.iMasterId = d.iFaTag left join mPay_Employee emp on emp.iMasterId = tg.iTag800 left join cCore_Vouchers_0 v on v.iVoucherType = h.iVoucherType  WHERE rma.sRmaNo = '{rmano}'  AND bSuspended = 0  AND d.iAuthStatus = 1   and h.iVoucherType = 3339 and not exists(select hh.iHeaderId from  tCore_Header_0 hh JOIN tCore_Data_0 dd ON hh.iHeaderId = dd.iHeaderId left join tCore_HeaderData1793_0 hhe on hhe.iHeaderId = hh.iHeaderId left join tCore_Rma_0 rrma on rrma.iBodyId = dd.iBodyId  where  hh.ivouchertype= 1793 and rrma.sRmaNo = '{rmano}' and hhe.POSDocNo = h.sVoucherNo)  ) posdt order by idate desc";
        }
        public static string GetSalesReturnSaleByDocNo(string docno)
        {
            return $"select * from (select * from (SELECT  h.sVoucherNo DocNo, h.idate,mbr.sName MemberName , mbr.iMasterId MemberId, cust.iMasterId CustomerId, cust.sName Customer,outl.iMasterId OutletId, outl.sName OutletName, cost.iMasterId CostCenterId, cost.sName CostCenterName, emp.iMasterId EmployeeId, emp.sName EmployeeName ,d.iBodyId BodyId,pr.iMasterId ItemId,pr.sCode ItemCode,pr.sName ItemName,muts.iMasterId UnitId, muts.sName UnitName,Price=abs(ind.mRate),'' RmaNo,1  Stock ,1 Qty, pru.VAT, dd.VoucherCode , sd.mVal1 VoucherDiscount, sd.mVal0 Discount,\r\nSoldRmasCount = (select count(srma.sRmaNo) from  tCore_Data_0 sd left join  tCore_Rma_0 srma on srma.iBodyId = sd.iBodyId where sd.iheaderid = h.iheaderid ),\r\nReturnedRmasCount = (select count(rrma.sRmaNo) from tCore_Header_0 rh join tCore_Data_0 rd on rd.iHeaderId = rh.iHeaderId left join tCore_HeaderData1793_0  rhe on rhe.iheaderid = rh.iheaderid left join tCore_Rma_0 rrma on rrma.iBodyId = rd.iBodyId where rh.iVoucherType = 1793 and rhe.POSDocNo = h.sVoucherNo), isnull(dd.LinkedItem,0) LinkedItem, isnull(dd.SchemeItem,'')  SchemeItem  FROM tCore_Header_0 h JOIN tCore_Data_0 d ON h.iHeaderId = d.iHeaderId  left join tCore_Data3334_0 dd on dd.iBodyId = d.iBodyId  left join  tCore_IndtaBodyScreenData_0 sd on sd.iBodyId = d.iBodyId  JOIN tCore_Indta_0 ind  ON d.iBodyId = ind.iBodyId join mcore_product pr on pr.imasterid = ind.iProduct join mucore_product pru on pru.imasterid = pr.iMasterId left join muCore_Product_Units uts on uts.iMasterId = pr.iMasterId left join mCore_Units muts on muts.iMasterId = uts.iDefaultSalesUnit left join tCore_Data_Tags_0 tg on tg.iBodyId = d.iBodyId left join mPos_Member mbr on mbr.iMasterId = tg.iTag1106 left join mCore_Account cust on cust.iMasterId = d.iBookNo left join mPos_Outlet outl on outl.iMasterId = d.iInvTag left join mCore_CostCenter cost on cost.iMasterId = d.iFaTag left join mPay_Employee emp on emp.iMasterId = tg.iTag800  WHERE h.sVoucherNo = '{docno}' AND bSuspended = 0  AND d.iAuthStatus = 1   and h.iVoucherType = 3334 \r\n ) dtt where ReturnedRmasCount < SoldRmasCount  \r\n       union      \r\n  select * from (SELECT  h.sVoucherNo DocNo, h.idate,mbr.sName MemberName , mbr.iMasterId MemberId, cust.iMasterId CustomerId, cust.sName Customer,outl.iMasterId OutletId, outl.sName OutletName, cost.iMasterId CostCenterId, cost.sName CostCenterName, emp.iMasterId EmployeeId, emp.sName EmployeeName ,d.iBodyId BodyId,pr.iMasterId ItemId,pr.sCode ItemCode,pr.sName ItemName,muts.iMasterId UnitId, muts.sName UnitName,Price=abs(ind.mRate),'' RmaNo,1  Stock ,1 Qty, pru.VAT,  '' VoucherCode , sd.mVal1 VoucherDiscount, sd.mVal0 Discount, SoldRmasCount = (select count(srma.sRmaNo) from  tCore_Data_0 sd left join  tCore_Rma_0 srma on srma.iBodyId = sd.iBodyId where sd.iheaderid = h.iheaderid ), ReturnedRmasCount = (select count(rrma.sRmaNo) from tCore_Header_0 rh join tCore_Data_0 rd on rd.iHeaderId = rh.iHeaderId left join tCore_HeaderData1793_0  rhe on rhe.iheaderid = rh.iheaderid left join tCore_Rma_0 rrma on rrma.iBodyId = rd.iBodyId where rh.iVoucherType = 1793 and rhe.POSDocNo = h.sVoucherNo), '' LinkedItem, '' SchemeItem   FROM tCore_Header_0 h JOIN tCore_Data_0 d ON h.iHeaderId = d.iHeaderId  left join tCore_Data3339_0 dd on dd.iBodyId = d.iBodyId  left join  tCore_IndtaBodyScreenData_0 sd on sd.iBodyId = d.iBodyId  JOIN tCore_Indta_0 ind  ON d.iBodyId = ind.iBodyId join mcore_product pr on pr.imasterid = ind.iProduct join mucore_product pru on pru.imasterid = pr.iMasterId left join muCore_Product_Units uts on uts.iMasterId = pr.iMasterId left join mCore_Units muts on muts.iMasterId = uts.iDefaultSalesUnit left join tCore_Data_Tags_0 tg on tg.iBodyId = d.iBodyId left join mPos_Member mbr on mbr.iMasterId = tg.iTag1106 left join mCore_Account cust on cust.iMasterId = d.iBookNo left join mPos_Outlet outl on outl.iMasterId = d.iInvTag left join mCore_CostCenter cost on cost.iMasterId = d.iFaTag left join mPay_Employee emp on emp.iMasterId = tg.iTag800  WHERE h.sVoucherNo = '{docno}' AND bSuspended = 0  AND d.iAuthStatus = 1   and h.iVoucherType = 3339   ) dtt where ReturnedRmasCount < SoldRmasCount  ) possale order by idate desc ";
        }
